const body = $input.first().json.body || $input.first().json;

const data = {
  call_id: body.call_id || '',
  caller_phone: body.caller_phone || '',
  caller_name: body.caller_name || body.patient_name || '',
  question: body.faq_question || body.question || body.transcript || '',
  intent: body.intent || 'faq',
  platform: body.platform || '',
  timestamp: new Date().toISOString()
};

return [{ json: data }];

const aiResponse = $input.first().json;
const prevData = $('Parse FAQ Request').first().json;

// Extract answer from OpenAI response
const answer = aiResponse.choices?.[0]?.message?.content || aiResponse.message?.content || aiResponse.text || 'I apologize, but I was unable to generate an answer. Please contact our office directly.';

// Check if AI flagged as needing human escalation
const needsEscalation = answer.toLowerCase().includes('speak with our staff') || 
                        answer.toLowerCase().includes('contact our office') ||
                        answer.toLowerCase().includes('recommend calling');

return [{
  json: {
    ...prevData,
    answer: answer,
    needs_escalation: needsEscalation,
    sms_response: `Hi ${prevData.caller_name || 'there'}! Regarding your question: ${answer} Need more help? Call us at ${$env.DENTAL_CLINIC_PHONE || 'the clinic'}.`
  }
}];
